INSERT INTO `wl_auto_respond_mails` (`id`, `email_section`, `email_subject`, `email_content`, `status`, `updated_on`) VALUES
(1, 'Member Registration ', 'Welcome to {site_name}', '<table border=\"0\" style=\"width:100%\">\n <tbody>\n  <tr>\n   <td colspan=\"2\"><strong>Hi {mem_name},</strong></td>\n  </tr>\n  <tr>\n   <td colspan=\"2\">We are happy to have you as the newest member of {site_name}!</td>\n  </tr>\n  <tr>\n   <td colspan=\"2\">This is a registration email as per the details submitted by you. You are now registered on {site_name} with the following details::</td>\n  </tr>\n  <tr>\n   <td colspan=\"2\"> </td>\n  </tr>\n  <tr>\n   <td><strong>Email ID:</strong></td>\n   <td>{username}</td>\n  </tr>\n  <tr>\n   <td><strong>Password:</strong></td>\n   <td>{password}</td>\n  </tr>\n  <tr>\n   <td colspan=\"2\"> </td>\n  </tr>\n  <tr>\n   <td colspan=\"2\">Thanks again. We hope you will visit us again soon and put these special services to work for you.<br />\n   Please feel free to contact us if you have any questions at all.</td>\n  </tr>\n  <tr>\n   <td colspan=\"2\"> </td>\n  </tr>\n  <tr>\n   <td colspan=\"2\">Thank you.<br />\n   {site_name} Customer Service<br />\n   Email: {admin_email}</td>\n  </tr>\n  <tr>\n   <td colspan=\"2\" style=\"text-align:center\">{site_name}. All right reserved.</td>\n  </tr>\n </tbody>\n</table>', '1', '2016-07-13 12:30:43'),
(2, 'Forgot Password', 'Forgot Password', '<table border=\"0\" style=\"width:100%\">\r\n <tbody>\r\n  <tr>\r\n   <td colspan=\"2\"><strong>Hi {mem_name},</strong></td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Your login details are as follows:</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Email ID:</strong></td>\r\n   <td>{username}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>password:</strong></td>\r\n   <td>{password}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Click here to login {link}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Thank you.<br />\r\n   {site_name} Customer Service<br />\r\n   Email: {admin_email}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\" style=\"text-align:center\">{site_name}. All right reserved.</td>\r\n  </tr>\r\n </tbody>\r\n</table>', '1', '2016-07-13 12:31:11'),
(3, 'Refer To Friends', 'Refer a Friend', '<table align=\"center\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"border:2px solid rgb(233, 233, 233); margin-top:10px; width:600px\">\r\n <tbody>\r\n  <tr>\r\n   <td style=\"text-align:left\">Hi {friend_name},</td>\r\n  </tr>\r\n  <tr>\r\n   <td>\r\n   <p>{your_name} has recommended this {text}, as {your_name} thinks you would like it.<br />\r\n   <br />\r\n   To view the Deal details please click on the following link.<br />\r\n   <br />\r\n   {site_link}</p>\r\n\r\n   <p> </p>\r\n\r\n   <p>Thanks and Regards,</p>\r\n\r\n   <p>{site_name} Team</p>\r\n   </td>\r\n  </tr>\r\n  <tr>\r\n   <td style=\"text-align:center\">{site_name}. All right reserved.</td>\r\n  </tr>\r\n </tbody>\r\n</table>', '2', '2016-07-13 12:30:51'),
(4, 'Church Registration', 'Church Registered on', '<table border=\"0\" style=\"width:100%\">\r\n <tbody>\r\n  <tr>\r\n   <td colspan=\"2\"><strong>Hi {mem_name},</strong></td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">A new church has registered on {site_name} with the following details:</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Church Name:</strong></td>\r\n   <td>{church_name}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Email ID:</strong></td>\r\n   <td>{church_email}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Contact Person Name:</strong></td>\r\n   <td>{contact_person_name}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Church Contact Number:</strong></td>\r\n   <td>{church_contact_number}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Church Address:</strong></td>\r\n   <td>{church_address}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Church Paypal ID:</strong></td>\r\n   <td>{church_paypal_id}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Thanks again</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Thank you.<br />\r\n   {site_name} Customer Service<br />\r\n   Email: {admin_email}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\" style=\"text-align:center\">{site_name}. All right reserved.</td>\r\n  </tr>\r\n </tbody>\r\n</table>', '2', '2017-08-23 18:16:24'),
(5, 'Contact Us', 'Enquiry', '<table border=\"0\" style=\"width:100%\">\r\n <tbody>\r\n  <tr>\r\n   <td colspan=\"2\"><strong>Dear {mem_name}</strong></td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Enquiry has been submitted with following info :</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Email:</strong></td>\r\n   <td>{email}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Phone no.:</strong></td>\r\n   <td>{phone}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Mobile no.:</strong></td>\r\n   <td>{mobile}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Company Name:</strong></td>\r\n   <td>{company}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Comments:</strong></td>\r\n   <td>{comments}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">{link} to login</td>\r\n  </tr>\r\n </tbody>\r\n</table>\r\n\r\n<p><br />\r\nThank you.<br />\r\n{site_name} Customer Service<br />\r\nEmail: {admin_email}</p>', '1', '2016-07-13 12:31:26'),
(6, 'Admin Registration ', 'Welcome to {site_name}', '<table border=\"0\" style=\"width:100%\">\r\n <tbody>\r\n  <tr>\r\n   <td colspan=\"2\"><strong>Hi Admin,</strong></td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">This is a registration email as per the details submitted by you. You are now registered on {site_name} with the following details:</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Name:</strong></td>\r\n   <td>{name}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Email ID:</strong></td>\r\n   <td>{username}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Password:</strong></td>\r\n   <td>{password}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Thanks again. We hope you will visit us again soon and put these special services to work for you.<br />\r\n   Please feel free to contact us if you have any questions at all.</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Thank you.<br />\r\n   {site_name} Customer Service<br />\r\n   Email: {admin_email}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\" style=\"text-align:center\">{site_name}. All right reserved.</td>\r\n  </tr>\r\n </tbody>\r\n</table>', '1', '2016-07-13 12:31:35'),
(7, 'Product Enquiry', 'Welcome to {site_name}', '<table border=\"0\" style=\"width:100%\">\r\n <tbody>\r\n  <tr>\r\n   <td colspan=\"2\"><strong>Hi Admin,</strong></td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">This is a registration email as per the details submitted by you. You are now registered on {site_name} with the following details:</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Name:</strong></td>\r\n   <td>{name}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Email ID:</strong></td>\r\n   <td>{username}</td>\r\n  </tr>\r\n  <tr>\r\n   <td><strong>Password:</strong></td>\r\n   <td>{password}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Thanks again. We hope you will visit us again soon and put these special services to work for you.<br />\r\n   Please feel free to contact us if you have any questions at all.</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\"> </td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\">Thank you.<br />\r\n   {site_name} Customer Service<br />\r\n   Email: {admin_email}</td>\r\n  </tr>\r\n  <tr>\r\n   <td colspan=\"2\" style=\"text-align:center\">{site_name}. All right reserved.</td>\r\n  </tr>\r\n </tbody>\r\n</table>', '1', '2016-07-13 12:31:35');
