(2, 0, 'Contact Us', 'contactus', '<div class=\"col-lg-4\">\r\n<div class=\"contact_area\">\r\n<div class=\"cnt_heading\">Registered Office</div>\r\n\r\n<div class=\"sec_cnt\">33 & 33A, Rama Road, Industrial Area,<br />\r\nNear Kirti Nagar Metro Station,<br />\r\nNew Delhi - 110015 (INDIA)</div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"col-lg-4\">\r\n<div class=\"contact_area\">\r\n<div class=\"cnt_heading\">Phone</div>\r\n\r\n<div class=\"sec_cnt black\">\r\n<div>+91-11-47584787</div>\r\n\r\n<div class=\"mt10\">+ 91 - 8854874587</div>\r\n</div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"col-lg-4\">\r\n<div class=\"contact_area\">\r\n<div class=\"cnt_heading\">Email</div>\r\n\r\n<div class=\"sec_cnt\">\r\n<div class=\"red\"><a href=\"mailto:info@djsouq.com\">info@djsouq.com</a></div>\r\n</div>\r\n</div>\r\n</div>\r\n', '', '', '2', '2019-11-26 09:49:44'),
