(9, 0, 'Our Vision', 'vision', 'Our Vision  contents...  ', NULL, '', '2', '2017-08-29 10:27:18'),
(10, 0, 'Shipping Information', 'shipping-information', '<p>We want you to love the products that you buy from us. In case you are not satisfied with your purchase, drop us a mail within 2 days of delivery with details at care@maquillagewellness.com with &ldquo;Returns and Replacement&rdquo; as a subject and we will get back to you</p>\r\n\r\n<p><strong>In case you received the wrong item.</strong></p>\r\n\r\n<p>Drop us an email at care@maquillagewellness.com&nbsp;within 2 days of the date of delivery. Our Customer delight team will resolve it at the earliest.&nbsp;</p>\r\n\r\n<p><strong>In case you received a damaged item.</strong></p>\r\n\r\n<p>Drop us an email with your order id and the picture of the damaged product at care@maquillagewellness.com within 2 days of the date of delivery. Our customer delight team will help you with your queries and resolve them at the earliest.</p>\r\n\r\n<p><strong>In case you need to cancel your order.</strong></p>\r\n\r\n<p>You can cancel an order within 3 hours of placing the order.</p>\r\n\r\n<p><strong>Shipping charges on purchase.</strong></p>\r\n\r\n<p>We offer FREE Shipping on all orders above Rs.499, which is notified from time to time. We also offer Free Cash-On-Delivery. You should consider the shipping rates shown at the time of check-out to be final.</p>\r\n\r\n<p><strong>Note:-&nbsp;</strong>Order will be shipped within 24hrs of placing the orders.</p>\r\n\r\n<p><strong>Conditions where a product can be returned or refunded:</strong></p>\r\n\r\n<ul>\r\n	<li>Wrong product delivered</li>\r\n	<li>Expired product delivered</li>\r\n	<li>Damaged product delivered &ndash; Physical damage/ tampered product or packaging</li>\r\n	<li>Incomplete order &ndash; missing products</li>\r\n</ul>\r\n\r\n<p><strong>Note:-</strong>&nbsp;Kindly allow 36 - 48 hrs to process the refund. Refunds will be processed using same payment method using which the payment accepted.</p>\r\n\r\n<p><strong>Conditions where refund/return requests will not be processed</strong></p>\r\n\r\n<ul>\r\n	<li>Opened/ used/ altered products.</li>\r\n	<li>Original packaging (mono cartons, labels, etc.) missing.</li>\r\n	<li>The return/ replacement request is generated after 7 days from the date of delivery.</li>\r\n	<li>The damaged/ missing product is reported after 2 days from the date of delivery.</li>\r\n	<li>any orders placed during the offer period, valid across all products available on the website, will not be entertained for cancellations, returns &amp; refunds</li>\r\n</ul>\r\n\r\n<p><strong>Note:&nbsp;</strong>In case of unforeseen circumstances, the brand reserves full rights to void the shipment and process a refund in case of the&nbsp;applicable&nbsp;order.</p>\r\n', NULL, '', '2', '2023-08-30 14:44:46'),
