INSERT INTO `wl_products` (`products_id`, `category_id`, `category_links`, `product_name`, `friendly_url`, `product_code`, `product_price`, `product_discounted_price`, `product_discount_percent`, `product_tax`, `products_description`, `products_specification`, `products_offer`, `return_policy`, `is_cod`, `gst`, `youtube_video`, `product_color_ids`, `product_size_ids`, `brand_id`, `location_id`, `style_id`, `material_id`, `is_hot`, `is_new`, `is_featured`, `is_popular`, `is_deal`, `deal_price`, `from_date`, `fromdate_strtotime`, `end_date`, `end_date_strtotome`, `exclusive_deal`, `from_date_exclusive`, `end_date_exclusive`, `fromdate_strtotime_exclusive`, `end_date_strtotome_exclusive`, `product_quantity`, `used_quantity`, `low_stocks`, `shipping_text`, `status`, `product_added_date`, `product_updated_date`, `products_viewed`, `product_alt`, `product_weight`, `xls_type`, `product_brochure`, `product_size_chart`, `max_sold_qty`, `deal_from_date`, `deal_end_date`, `vat_type`, `vat_rate`, `seller_name`, `in_stock`) VALUES
(1, 9, '9,1', 'CHOCO CHOCOLATE', 'choco-chocolate', 'C-123', 100.00, 99.00, 0.00, 0.00, '<div class=\"Y3BBE\">Chocolate is a sweet or semi-sweet food product made from roasted and ground cocoa beans, used as a candy or to flavor other foods. It can be a solid, paste, or liquid, and its flavor varies from bitter to very sweet depending on the additions of sugar, milk, or other ingredients. The base ingredient, cocoa beans, are fermented and dried to develop their flavor before processing into the chocolate we consume. </div>\r\n\r\n<div class=\"Fsg96\"> </div>\r\n\r\n<div class=\"otQkpb\">What chocolate is made from</div>\r\n\r\n<ul>\r\n <li>Cocoa beans: The seeds of the cacao tree, which are fermented, dried, cleaned, and roasted to develop their flavor.</li>\r\n <li>Chocolate liquor: A paste made from ground, roasted cocoa beans. It is the base for all chocolate products.</li>\r\n <li>Cocoa butter: The natural fat extracted from cocoa beans.</li>\r\n <li>Cocoa solids: The non-fat parts of the cocoa bean, which give chocolate its flavor and color. </li>\r\n</ul>\r\n\r\n<div class=\"Fsg96\"> </div>\r\n\r\n<div class=\"otQkpb\">Types of chocolate and their characteristics</div>\r\n\r\n<ul>\r\n <li><a href=\"https://www.google.com/search?q=Dark+chocolate&oq=CHOCLATE+DES&aqs=chrome.5.69i57j0i10i11i512l3j46i10i11i175i199i512i654j0i10i11i512l5.5370j0j7&sourceid=chrome&ie=UTF-8&ved=2ahUKEwiAhJ2yv-mQAxV1ALkGHW41C1wQgK4QegYIAQgAEBM\">Dark chocolate</a>: Made from cocoa solids, cocoa butter, and sugar. It has a more bitter taste than milk chocolate.</li>\r\n <li><a href=\"https://www.google.com/search?q=Milk+chocolate&oq=CHOCLATE+DES&aqs=chrome.5.69i57j0i10i11i512l3j46i10i11i175i199i512i654j0i10i11i512l5.5370j0j7&sourceid=chrome&ie=UTF-8&ved=2ahUKEwiAhJ2yv-mQAxV1ALkGHW41C1wQgK4QegYIAQgAEBU\">Milk chocolate</a>: Contains added milk solids (powdered or condensed) in addition to cocoa, cocoa butter, and sugar.</li>\r\n <li><a href=\"https://www.google.com/search?q=White+chocolate&oq=CHOCLATE+DES&aqs=chrome.5.69i57j0i10i11i512l3j46i10i11i175i199i512i654j0i10i11i512l5.5370j0j7&sourceid=chrome&ie=UTF-8&ved=2ahUKEwiAhJ2yv-mQAxV1ALkGHW41C1wQgK4QegYIAQgAEBc\">White chocolate</a>: Made with cocoa butter, sugar, and milk, but does not contain cocoa solids. It is technically not considered chocolate by some standards because it lacks the cocoa solids.</li>\r\n <li><a href=\"https://www.google.com/search?q=Baking+chocolate&oq=CHOCLATE+DES&aqs=chrome.5.69i57j0i10i11i512l3j46i10i11i175i199i512i654j0i10i11i512l5.5370j0j7&sourceid=chrome&ie=UTF-8&ved=2ahUKEwiAhJ2yv-mQAxV1ALkGHW41C1wQgK4QegYIAQgAEBk\">Baking chocolate</a>: Unsweetened chocolate liquor that is hardened into a block for baking. </li>\r\n</ul>\r\n\r\n<div class=\"Fsg96\"> </div>\r\n\r\n<div class=\"otQkpb\">Other uses of chocolate</div>\r\n\r\n<ul>\r\n <li>Beverage: Chocolate is used to make hot or cold drinks, often called hot chocolate or cocoa.</li>\r\n <li>Confectionery: It is used in a wide variety of candies and is often used to coat other sweets.</li>\r\n <li>Desserts: It is a common flavoring for cakes, cookies, ice cream, and puddings.</li>\r\n <li>Color: The word \"chocolate\" is also used to describe a dark brown color. </li>\r\n</ul>\r\n', NULL, NULL, NULL, NULL, 0, 'https://youtu.be/TovdVOcUnDw?si=n2Idzew_rx37Vu-c', '3,4', '1,2', NULL, NULL, 0, 0, '1', '1', '1', '0', '0', 0.00, NULL, NULL, NULL, NULL, '0', NULL, NULL, NULL, NULL, 1, 0, 0, NULL, '1', '2025-11-11 12:28:20', NULL, 0, '', NULL, '0', NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, '1'),
(2, 9, '9,1', 'Brookside Dark Chocolate, Pomegranate, Truffles', 'brookside-dark-chocolate-pomegranate-truffles', 'C-001', 100.00, 90.00, 0.00, 0.00, '<p xss=removed>\"Sed ut perspiciatis unde omnis iste natus error sit voluptatem accusantium doloremque laudantium, totam rem aperiam, eaque ipsa quae ab illo inventore veritatis et quasi architecto beatae vitae dicta sunt explicabo. Nemo enim ipsam voluptatem quia voluptas sit aspernatur aut odit aut fugit, sed quia consequuntur magni dolores eos qui ratione voluptatem sequi nesciunt. Neque porro quisquam est, qui dolorem ipsum quia dolor sit amet, consectetur, adipisci velit, sed quia non numquam eius modi tempora incidunt ut labore et dolore magnam aliquam quaerat voluptatem. Ut enim ad minima veniam, quis nostrum exercitationem ullam corporis suscipit laboriosam, nisi ut aliquid ex ea commodi consequatur? Quis autem vel eum iure reprehenderit qui in ea voluptate velit esse quam nihil molestiae consequatur, vel illum qui dolorem eum fugiat quo voluptas nulla pariatur?\"</p>\r\n\r\n<div> </div>\r\n', NULL, NULL, NULL, NULL, 0, '&lt;iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d14026.450479715324!2d77.08584673243533!3d28.491210661870117!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x390d193152e86913:0xa87741fab1e85eed!2sU Block, DLF Phase 3, Sector 24, Gurugram, Haryana 122022!5e0!3m2!1sen!2sin!4v1681969616611!5m2!1sen!2sin\" width=\"600\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"&gt;&lt;', '5', '1', NULL, NULL, 0, 0, '1', '1', '1', '0', '0', 0.00, NULL, NULL, NULL, NULL, '0', NULL, NULL, NULL, NULL, 0, 0, 0, NULL, '1', '2025-11-12 11:49:34', NULL, 0, '', NULL, '0', NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, '2'),
